// Types
// ─────────────────────────────────────────────────────────────

export interface SubtitleCue {
  id: number;
  startTime: number; // milliseconds
  endTime: number; // milliseconds
  text: string;
  speaker?: string;
  style?: SubtitleStyleConfig;
}

export interface SubtitleStyleConfig {
  preset: SubtitlePreset;
  fontSize: number;
  color: string;
  backgroundColor: string;
  position: 'top' | 'middle' | 'bottom';
  bold: boolean;
  italic: boolean;
}

export type SubtitlePreset = 'default' | 'netflix' | 'minimal' | 'bold';

export interface SubtitlesEditorProps {
  /** Initial cues to display */
  initialCues?: SubtitleCue[];
  /** Total video duration in ms */
  totalDuration?: number;
  /** Scenes data for Whisper generation context */
  scenes?: Array<{ script?: string; duration?: number }>;
  /** Project ID for API calls */
  projectId?: string;
  /** Callback when cues change */
  onCuesChange?: (cues: SubtitleCue[]) => void;
  /** Callback when requesting burn-in */
  onBurnIn?: (cues: SubtitleCue[], style: SubtitlePreset) => void;
  /** Current playback time in ms (for highlighting active cue) */
  currentTime?: number;
  /** Additional CSS class */
  className?: string;
}

