/**
 * Format milliseconds as display time (MM:SS.mmm)
 */
export function formatTimeDisplay(ms: number): string {
  const totalSeconds = Math.max(0, ms / 1000);
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = Math.floor(totalSeconds % 60);
  const millis = Math.round((totalSeconds % 1) * 1000);
  return `${minutes.toString().padStart(2, '0')}:${seconds
    .toString()
    .padStart(2, '0')}.${millis.toString().padStart(3, '0')}`;
}

/**
 * Parse display time string back to milliseconds
 */
export function parseTimeInput(input: string): number | null {
  // Formats: MM:SS.mmm, MM:SS, SS.mmm, SS
  const fullMatch = input.match(/^(\d{1,3}):(\d{2})\.(\d{1,3})$/);
  if (fullMatch) {
    const mins = parseInt(fullMatch[1], 10);
    const secs = parseInt(fullMatch[2], 10);
    const ms = parseInt(fullMatch[3].padEnd(3, '0'), 10);
    if (secs >= 60 || ms >= 1000) return null;
    return (mins * 60 + secs) * 1000 + ms;
  }

  const minSecMatch = input.match(/^(\d{1,3}):(\d{2})$/);
  if (minSecMatch) {
    const mins = parseInt(minSecMatch[1], 10);
    const secs = parseInt(minSecMatch[2], 10);
    if (secs >= 60) return null;
    return (mins * 60 + secs) * 1000;
  }

  const secMsMatch = input.match(/^(\d+)\.(\d{1,3})$/);
  if (secMsMatch) {
    const secs = parseInt(secMsMatch[1], 10);
    const ms = parseInt(secMsMatch[2].padEnd(3, '0'), 10);
    if (ms >= 1000) return null;
    return secs * 1000 + ms;
  }

  const secMatch = input.match(/^(\d+)$/);
  if (secMatch) {
    return parseInt(secMatch[1], 10) * 1000;
  }

  return null;
}

/**
 * Generate SRT content from cues
 */
export function cuesToSRT(cues: SubtitleCue[]): string {
  return cues
    .map((cue, i) => {
      const start = formatSRTTimestamp(cue.startTime);
      const end = formatSRTTimestamp(cue.endTime);
      return `${i + 1}\n${start} --> ${end}\n${cue.text}\n`;
    })
    .join('\n');
}

/**
 * Generate VTT content from cues
 */
export function cuesToVTT(cues: SubtitleCue[]): string {
  const body = cues
    .map((cue, i) => {
      const start = formatVTTTimestamp(cue.startTime);
      const end = formatVTTTimestamp(cue.endTime);
      return `${i + 1}\n${start} --> ${end}\n${cue.text}\n`;
    })
    .join('\n');
  return `WEBVTT\n\n${body}`;
}

/**
 * Format milliseconds as SRT timestamp (HH:MM:SS,mmm)
 */
export function formatSRTTimestamp(ms: number): string {
  const totalSeconds = Math.max(0, ms / 1000);
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = Math.floor(totalSeconds % 60);
  const millis = Math.round((totalSeconds % 1) * 1000);
  return `${hours.toString().padStart(2, '0')}:${minutes
    .toString()
    .padStart(2, '0')}:${seconds.toString().padStart(2, '0')},${millis
    .toString()
    .padStart(3, '0')}`;
}

/**
 * Format milliseconds as VTT timestamp (HH:MM:SS.mmm)
 */
export function formatVTTTimestamp(ms: number): string {
  return formatSRTTimestamp(ms).replace(',', '.');
}

/**
 * Parse SRT content into cues
 */
export function parseSRTContent(srt: string): SubtitleCue[] {
  const cues: SubtitleCue[] = [];
  const blocks = srt.trim().split(/\n\n+/);

  for (const block of blocks) {
    const lines = block.split('\n');
    if (lines.length < 3) continue;

    const id = parseInt(lines[0], 10);
    if (isNaN(id)) continue;

    const timeMatch = lines[1].match(/(\d{2}:\d{2}:\d{2},\d{3})\s*-->\s*(\d{2}:\d{2}:\d{2},\d{3})/);
    if (!timeMatch) continue;

    const startTime = parseSRTTimestamp(timeMatch[1]);
    const endTime = parseSRTTimestamp(timeMatch[2]);
    const text = lines.slice(2).join('\n');

    cues.push({ id, startTime, endTime, text });
  }

  return cues;
}

/**
 * Parse SRT timestamp to milliseconds
 */
export function parseSRTTimestamp(ts: string): number {
  const match = ts.match(/(\d{2}):(\d{2}):(\d{2}),(\d{3})/);
  if (!match) return 0;
  const h = parseInt(match[1], 10);
  const m = parseInt(match[2], 10);
  const s = parseInt(match[3], 10);
  const ms = parseInt(match[4], 10);
  return (h * 3600 + m * 60 + s) * 1000 + ms;
}

/**
 * Validate a cue (endTime > startTime, non-empty text)
 */
export function validateCue(cue: SubtitleCue): string[] {
  const errors: string[] = [];
  if (cue.startTime < 0) errors.push('Tempo inicial negativo');
  if (cue.endTime <= cue.startTime) errors.push('Tempo final deve ser maior que o inicial');
  if (!cue.text.trim()) errors.push('Texto vazio');
  return errors;
}

/**
 * Calculate cue duration in ms
 */
export function cueDuration(cue: SubtitleCue): number {
  return Math.max(0, cue.endTime - cue.startTime);
}

/**
 * Find the active cue at a given playback time
 */
export function findActiveCue(cues: SubtitleCue[], timeMs: number): SubtitleCue | null {
  return cues.find((c) => timeMs >= c.startTime && timeMs < c.endTime) ?? null;
}

/**
 * Sort cues by startTime
 */
export function sortCuesByTime(cues: SubtitleCue[]): SubtitleCue[] {
  return [...cues].sort((a, b) => a.startTime - b.startTime).map((c, i) => ({ ...c, id: i + 1 }));
}

/**
 * Count total words in all cues
 */
export function totalWordCount(cues: SubtitleCue[]): number {
  return cues.reduce((sum, cue) => sum + cue.text.split(/\s+/).filter(Boolean).length, 0);
}

/**
 * Calculate estimated reading speed (words per minute) from cues
 */
export function estimateWPM(cues: SubtitleCue[]): number {
  if (cues.length === 0) return 0;
  const totalMs = cues.reduce((sum, c) => sum + cueDuration(c), 0);
  if (totalMs === 0) return 0;
  const words = totalWordCount(cues);
  return Math.round((words / totalMs) * 60000);
}

