// ─────────────────────────────────────────────────────────────

interface CueRowProps {
  cue: SubtitleCue;
  isActive: boolean;
  onChange: (cue: SubtitleCue) => void;
  onDelete: () => void;
  onMoveUp: () => void;
  onMoveDown: () => void;
  isFirst: boolean;
  isLast: boolean;
}

function CueRow({
  cue,
  isActive,
  onChange,
  onDelete,
  onMoveUp,
  onMoveDown,
  isFirst,
  isLast,
}: CueRowProps) {
  const [editingStart, setEditingStart] = useState(false);
  const [editingEnd, setEditingEnd] = useState(false);
  const [startInput, setStartInput] = useState('');
  const [endInput, setEndInput] = useState('');
  const errors = useMemo(() => validateCue(cue), [cue]);

  const commitStartTime = useCallback(() => {
    const parsed = parseTimeInput(startInput);
    if (parsed !== null && parsed < cue.endTime) {
      onChange({ ...cue, startTime: parsed });
    }
    setEditingStart(false);
  }, [startInput, cue, onChange]);

  const commitEndTime = useCallback(() => {
    const parsed = parseTimeInput(endInput);
    if (parsed !== null && parsed > cue.startTime) {
      onChange({ ...cue, endTime: parsed });
    }
    setEditingEnd(false);
  }, [endInput, cue, onChange]);

  return (
    <div
      className={`group border rounded-lg p-3 transition-colors ${
        isActive
          ? 'border-blue-500 bg-blue-500/10'
          : errors.length > 0
            ? 'border-red-500/50 bg-red-500/5'
            : 'border-zinc-700 bg-zinc-800/50 hover:border-zinc-600'
      }`}
    >
      {/* Header: ID + timing */}
      <div className="flex items-center gap-2 mb-2">
        <Badge variant="outline" className="text-xs font-mono">
          #{cue.id}
        </Badge>

        {/* Start time */}
        <div className="flex items-center gap-1">
          <Clock className="h-3 w-3 text-zinc-500" />
          {editingStart ? (
            <Input
              value={startInput}
              onChange={(e) => setStartInput(e.target.value)}
              onBlur={commitStartTime}
              onKeyDown={(e) => e.key === 'Enter' && commitStartTime()}
              className="h-6 w-24 text-xs font-mono px-1"
              autoFocus
            />
          ) : (
            <button
              className="text-xs font-mono text-zinc-400 hover:text-white cursor-pointer"
              onClick={() => {
                setStartInput(formatTimeDisplay(cue.startTime));
                setEditingStart(true);
              }}
            >
              {formatTimeDisplay(cue.startTime)}
            </button>
          )}
        </div>

        <span className="text-zinc-600">→</span>

        {/* End time */}
        {editingEnd ? (
          <Input
            value={endInput}
            onChange={(e) => setEndInput(e.target.value)}
            onBlur={commitEndTime}
            onKeyDown={(e) => e.key === 'Enter' && commitEndTime()}
            className="h-6 w-24 text-xs font-mono px-1"
            autoFocus
          />
        ) : (
          <button
            className="text-xs font-mono text-zinc-400 hover:text-white cursor-pointer"
            onClick={() => {
              setEndInput(formatTimeDisplay(cue.endTime));
              setEditingEnd(true);
            }}
          >
            {formatTimeDisplay(cue.endTime)}
          </button>
        )}

        {/* Duration badge */}
        <Badge variant="secondary" className="text-xs ml-auto">
          {(cueDuration(cue) / 1000).toFixed(1)}s
        </Badge>

        {/* Actions */}
        <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
          <Button
            variant="ghost"
            size="icon"
            className="h-6 w-6"
            onClick={onMoveUp}
            disabled={isFirst}
          >
            <ChevronUp className="h-3 w-3" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="h-6 w-6"
            onClick={onMoveDown}
            disabled={isLast}
          >
            <ChevronDown className="h-3 w-3" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="h-6 w-6 text-red-400 hover:text-red-300"
            onClick={onDelete}
          >
            <Trash2 className="h-3 w-3" />
          </Button>
        </div>
      </div>

      {/* Text area */}
      <textarea
        value={cue.text}
        onChange={(e) => onChange({ ...cue, text: e.target.value })}
        className="w-full bg-transparent border border-zinc-700 rounded px-2 py-1.5 text-sm text-zinc-200 placeholder-zinc-600 resize-none focus:outline-none focus:border-blue-500 transition-colors"
        rows={2}
        placeholder="Texto da legenda..."
      />

      {/* Error display */}
      {errors.length > 0 && <div className="mt-1 text-xs text-red-400">{errors.join(', ')}</div>}
    </div>
  );
}

interface TimelineBarProps {
  cues: SubtitleCue[];
  totalDuration: number;
  currentTime?: number;
  activeCueId?: number;
}

function TimelineBar({ cues, totalDuration, currentTime, activeCueId }: TimelineBarProps) {
  if (totalDuration <= 0) return null;

  return (
    <div className="relative w-full h-8 bg-zinc-800 rounded overflow-hidden border border-zinc-700">
      {/* Cue blocks */}
      {cues.map((cue) => {
        const left = (cue.startTime / totalDuration) * 100;
        const width = Math.max(0.5, ((cue.endTime - cue.startTime) / totalDuration) * 100);
        const isActive = cue.id === activeCueId;

        return (
          <div
            key={cue.id}
            className={`absolute top-1 bottom-1 rounded-sm transition-colors ${
              isActive ? 'bg-blue-500' : 'bg-zinc-500 hover:bg-zinc-400'
            }`}
            style={{ left: `${left}%`, width: `${width}%` }}
            title={`#${cue.id}: ${cue.text.slice(0, 50)}`}
          />
        );
      })}

      {/* Playhead */}
      {currentTime !== undefined && currentTime >= 0 && (
        <div
          className="absolute top-0 bottom-0 w-0.5 bg-red-500 z-10"
          style={{ left: `${Math.min(100, (currentTime / totalDuration) * 100)}%` }}
        />
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
// Main Component
// ─────────────────────────────────────────────────────────────

export default function SubtitlesEditor({
  initialCues = [],
  totalDuration = 0,
  scenes,
  projectId,
  onCuesChange,
  onBurnIn,
  currentTime,
  className,
}: SubtitlesEditorProps) {
  const [cues, setCues] = useState<SubtitleCue[]>(initialCues);
  const [stylePreset, setStylePreset] = useState<SubtitlePreset>('default');
  const [generating, setGenerating] = useState(false);
  const [importing, setImporting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Derived state
  const activeCue = useMemo(
    () => (currentTime !== undefined ? findActiveCue(cues, currentTime) : null),
    [cues, currentTime],
  );
  const wordCount = useMemo(() => totalWordCount(cues), [cues]);
  const wpm = useMemo(() => estimateWPM(cues), [cues]);

  const effectiveDuration = useMemo(() => {
    if (totalDuration > 0) return totalDuration;
    if (cues.length > 0) return cues[cues.length - 1].endTime;
    return 60000; // fallback 1 min
  }, [totalDuration, cues]);

  // Cue mutations
  const updateCues = useCallback(
    (newCues: SubtitleCue[]) => {
      setCues(newCues);
      onCuesChange?.(newCues);
    },
    [onCuesChange],
  );

  const handleCueChange = useCallback(
    (updated: SubtitleCue) => {
      const newCues = cues.map((c) => (c.id === updated.id ? updated : c));
      updateCues(newCues);
    },
    [cues, updateCues],
  );

  const handleDeleteCue = useCallback(
    (id: number) => {
      const newCues = cues.filter((c) => c.id !== id).map((c, i) => ({ ...c, id: i + 1 }));
      updateCues(newCues);
    },
    [cues, updateCues],
  );

  const handleAddCue = useCallback(() => {
    const lastCue = cues[cues.length - 1];
    const startTime = lastCue ? lastCue.endTime + 100 : 0;
    const newCue: SubtitleCue = {
      id: cues.length + 1,
      startTime,
      endTime: startTime + 3000,
      text: '',
    };
    updateCues([...cues, newCue]);
  }, [cues, updateCues]);

  const handleMoveCue = useCallback(
    (id: number, direction: 'up' | 'down') => {
      const idx = cues.findIndex((c) => c.id === id);
      if (idx === -1) return;
      const targetIdx = direction === 'up' ? idx - 1 : idx + 1;
      if (targetIdx < 0 || targetIdx >= cues.length) return;

      const newCues = [...cues];
      [newCues[idx], newCues[targetIdx]] = [newCues[targetIdx], newCues[idx]];
      updateCues(newCues.map((c, i) => ({ ...c, id: i + 1 })));
    },
    [cues, updateCues],
  );

  // Generate subtitles from scenes via API
  const handleGenerate = useCallback(async () => {
    if (!scenes || scenes.length === 0) return;

    setGenerating(true);
    try {
      const slides = scenes
        .filter((s) => s.script?.trim())
        .map((s, i) => ({
          id: `slide-${i + 1}`,
          text: s.script || '',
          duration: s.duration || 10,
        }));

      if (slides.length === 0) return;

      const res = await fetch('/api/subtitles/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ slides, projectId }),
      });

      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.error || 'Falha ao gerar legendas');
      }

      const data = await res.json();
      if (!data.success) throw new Error(data.error || 'Erro na geração');

      // If SRT URL returned, fetch and parse it
      if (data.srtUrl) {
        const srtRes = await fetch(data.srtUrl);
        if (srtRes.ok) {
          const srtContent = await srtRes.text();
          const parsed = parseSRTContent(srtContent);
          if (parsed.length > 0) {
            updateCues(parsed);
            return;
          }
        }
      }

      // Fallback: generate from slides locally
      let currentTime = 0;
      const generatedCues: SubtitleCue[] = slides.map((slide, i) => {
        const start = currentTime;
        const end = currentTime + slide.duration * 1000;
        currentTime = end + 100;
        return {
          id: i + 1,
          startTime: start,
          endTime: end,
          text: slide.text,
        };
      });
      updateCues(generatedCues);
    } catch {
      // error handled silently, user sees button state
    } finally {
      setGenerating(false);
    }
  }, [scenes, projectId, updateCues]);

  // Import SRT file
  const handleImportFile = useCallback(
    async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setImporting(true);
      try {
        const text = await file.text();
        const parsed = parseSRTContent(text);
        if (parsed.length > 0) {
          updateCues(parsed);
        }
      } finally {
        setImporting(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    },
    [updateCues],
  );

  // Export as file download
  const handleExport = useCallback(
    (format: 'srt' | 'vtt') => {
      const content = format === 'srt' ? cuesToSRT(cues) : cuesToVTT(cues);
      const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `subtitles.${format}`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    },
    [cues],
  );

  // Copy to clipboard
  const handleCopyToClipboard = useCallback(
    async (format: 'srt' | 'vtt') => {
      const content = format === 'srt' ? cuesToSRT(cues) : cuesToVTT(cues);
      await navigator.clipboard.writeText(content);
    },
    [cues],
  );

  return (
    <div className={`flex flex-col h-full bg-zinc-900 text-white ${className || ''}`}>
      {/* Header / Toolbar */}
      <div className="flex items-center gap-2 p-3 border-b border-zinc-800">
        <TypeIcon className="h-4 w-4 text-blue-400" />
        <span className="text-sm font-medium">Legendas</span>
        <Badge variant="secondary" className="text-xs">
          {cues.length} cues
        </Badge>
        {wordCount > 0 && (
          <Badge variant="outline" className="text-xs">
            {wordCount} palavras · {wpm} wpm
          </Badge>
        )}

        <div className="ml-auto flex items-center gap-1">
          {/* Style preset selector */}
          <Select value={stylePreset} onValueChange={(v) => setStylePreset(v as SubtitlePreset)}>
            <SelectTrigger className="h-7 w-28 text-xs">
              <Palette className="h-3 w-3 mr-1" />
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {Object.entries(STYLE_PRESETS).map(([key, val]) => (
                <SelectItem key={key} value={key}>
                  <span className="text-xs">{val.label}</span>
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {/* Timeline bar */}
      <div className="px-3 py-2">
        <TimelineBar
          cues={cues}
          totalDuration={effectiveDuration}
          currentTime={currentTime}
          activeCueId={activeCue?.id}
        />
      </div>

      {/* Action buttons */}
      <div className="flex items-center gap-1 px-3 pb-2 flex-wrap">
        <Button
          variant="outline"
          size="sm"
          className="h-7 text-xs"
          onClick={handleGenerate}
          disabled={generating || !scenes || scenes.length === 0}
        >
          {generating ? (
            <Loader2 className="h-3 w-3 mr-1 animate-spin" />
          ) : (
            <Wand2 className="h-3 w-3 mr-1" />
          )}
          Gerar
        </Button>

        <Button
          variant="outline"
          size="sm"
          className="h-7 text-xs"
          onClick={() => fileInputRef.current?.click()}
          disabled={importing}
        >
          {importing ? (
            <Loader2 className="h-3 w-3 mr-1 animate-spin" />
          ) : (
            <Upload className="h-3 w-3 mr-1" />
          )}
          Importar
        </Button>
        <input
          ref={fileInputRef}
          type="file"
          accept=".srt,.vtt"
          className="hidden"
          onChange={handleImportFile}
        />

        <Separator orientation="vertical" className="h-4 mx-1" />

        <Button
          variant="outline"
          size="sm"
          className="h-7 text-xs"
          onClick={() => handleExport('srt')}
          disabled={cues.length === 0}
        >
          <Download className="h-3 w-3 mr-1" />
          SRT
        </Button>

        <Button
          variant="outline"
          size="sm"
          className="h-7 text-xs"
          onClick={() => handleExport('vtt')}
          disabled={cues.length === 0}
        >
          <Download className="h-3 w-3 mr-1" />
          VTT
        </Button>

        <Button
          variant="ghost"
          size="sm"
          className="h-7 text-xs"
          onClick={() => handleCopyToClipboard('srt')}
          disabled={cues.length === 0}
          title="Copiar SRT"
        >
          <Copy className="h-3 w-3" />
        </Button>

        <Separator orientation="vertical" className="h-4 mx-1" />

        {onBurnIn && (
          <Button
            variant="default"
            size="sm"
            className="h-7 text-xs"
            onClick={() => onBurnIn(cues, stylePreset)}
            disabled={cues.length === 0}
          >
            <Play className="h-3 w-3 mr-1" />
            Burn-in
          </Button>
        )}

        <Button variant="outline" size="sm" className="h-7 text-xs ml-auto" onClick={handleAddCue}>
          <Plus className="h-3 w-3 mr-1" />
          Cue
        </Button>
      </div>

      <Separator />

      {/* Cue list */}
      <ScrollArea className="flex-1">
        <div className="p-3 space-y-2">
          {cues.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-zinc-500">
              <FileText className="h-10 w-10 mb-3" />
              <p className="text-sm font-medium">Nenhuma legenda</p>
              <p className="text-xs mt-1">
                Clique em &quot;Gerar&quot; para criar legendas automaticamente ou em
                &quot;Importar&quot; para carregar um arquivo SRT/VTT.
              </p>
            </div>
          ) : (
            cues.map((cue, idx) => (
              <CueRow
                key={cue.id}
                cue={cue}
                isActive={activeCue?.id === cue.id}
                onChange={handleCueChange}
                onDelete={() => handleDeleteCue(cue.id)}
                onMoveUp={() => handleMoveCue(cue.id, 'up')}
                onMoveDown={() => handleMoveCue(cue.id, 'down')}
                isFirst={idx === 0}
                isLast={idx === cues.length - 1}
              />
            ))
          )}
        </div>
      </ScrollArea>
    </div>
  );
}
